macro.command:
for (eff of event.item.transferredEffects) {
if (eff.disabled) {await eff.update({disabled:false});}
else if (!eff.disabled) {await eff.update({disabled:true});}
}

let enhanceActions = actor.items.filter(y => y.system.id == "enhance");
for (let action of enhanceActions ) {
	if (actor.system.resources.inv.value >= 1 && actor.items.filter(x => x.name == 'Speak the Second Ideal' && x.type == 'goal')[0].system.level == 3) {
		await action.update({'system.activation.cost.type': "fre", 'system.activation.consume': []});
	} else {
		await action.update({'system.activation.cost.type': "act"});
		if (action.system.activation.consume.length < 1) {
			await action.update({'system.activation.consume': [{"type": "resource", "value": {"min": 1, "max": 1, "actual": 0}, "resource": "inv"}]});
		}
	}

}
